"use client";

import { type HorizontalStepperProps, HorizontalStepperRoot } from "./horizontal-stepper";
import { HorizontalStepperStep, type HorizontalStepperStepProps } from "./horizontal-stepper-step";

/** Sibling primitive: compact horizontal step bar. */
const HorizontalStepper = Object.assign(HorizontalStepperRoot, {
  Step: HorizontalStepperStep,
});

export { HorizontalStepper, type HorizontalStepperProps };
export { HorizontalStepperStep, type HorizontalStepperStepProps };
export type { HorizontalStepperVariant } from "@/lib/stepper-variants";
export { type StepStatus, useStepInfo } from "./horizontal-stepper-context";

"use client";

import { type ReactNode, useMemo } from "react";
import {
  type HorizontalStepperVariant,
  horizontalStepperRootVariants,
} from "@/lib/stepper-variants";
import { cn } from "@/lib/utils";
import { HorizontalStepperContext } from "./horizontal-stepper-context";

/** Props for horizontal stepper. */
export interface HorizontalStepperProps {
  /**
   * Ordered step ids. Used to compute status (completed/active/pending) for each step relative
   * to value.
   */
  steps: string[];
  /** Id of the active step. */
  value: string;
  /** Visual variant. Drives the indicator glyph, connector treatment, and label typography. */
  variant?: HorizontalStepperVariant;
  /** HorizontalStepper.Step children, one per id in steps. */
  children: ReactNode;
  /** Additional class names merged onto the rendered element. */
  className?: string;
  /** Accessible name for the <ol> list. */
  "aria-label"?: string;
}

/** Sibling primitive: compact horizontal step bar. */
export function HorizontalStepperRoot({
  steps,
  value,
  variant = "ascii",
  children,
  className,
  "aria-label": ariaLabel,
}: HorizontalStepperProps) {
  const contextValue = useMemo(() => ({ value, steps, variant }), [value, steps, variant]);

  return (
    <HorizontalStepperContext value={contextValue}>
      {/* biome-ignore lint/a11y/useSemanticElements: this already is an <ol>; the explicit role="list" below restores list semantics that Tailwind preflight strips, and Biome should not suggest swapping the element. */}
      <ol
        // biome-ignore lint/a11y/noRedundantRoles: Tailwind preflight sets list-style:none on <ol>, which drops list semantics in Safari/VoiceOver; role="list" restores them.
        role="list"
        aria-label={ariaLabel || "Progress"}
        data-slot="horizontal-stepper"
        data-variant={variant}
        className={cn(horizontalStepperRootVariants({ variant }), className)}
      >
        {children}
      </ol>
    </HorizontalStepperContext>
  );
}

"use client";

import { createContext, useContext } from "react";
import type { StepStatus } from "@/lib/step-status";
import type { HorizontalStepperVariant } from "@/lib/stepper-variants";

export type { StepStatus };

/** Allowed horizontal step status values. */
export type HorizontalStepStatus = Extract<StepStatus, "active" | "completed" | "pending">;

/** Context value shared by stepper. */
interface StepperContextValue {
  /** Id of the active step. */
  value: string;
  /**
   * Ordered step ids. Used to compute status (completed/active/pending) for each step relative
   * to value.
   */
  steps: string[];
  /** Visual variant. Controls the indicator glyph and connector treatment across every step. */
  variant: HorizontalStepperVariant;
}

/** React context backing horizontal stepper. */
export const HorizontalStepperContext = createContext<StepperContextValue | undefined>(undefined);

/** Reads the stepper context. */
export function useStepperContext() {
  const ctx = useContext(HorizontalStepperContext);
  if (ctx === undefined) {
    throw new Error("HorizontalStepperStep must be used within a HorizontalStepper");
  }
  return ctx;
}

/** Provides step info behavior. */
export function useStepInfo(value: string): { status: HorizontalStepStatus; index: number } {
  const { value: currentValue, steps } = useStepperContext();
  const stepIndex = steps.indexOf(value);
  const currentIndex = steps.indexOf(currentValue);

  if (stepIndex === currentIndex) return { status: "active", index: stepIndex };
  if (stepIndex < currentIndex) return { status: "completed", index: stepIndex };
  return { status: "pending", index: stepIndex };
}

"use client";

import type { ReactNode } from "react";
import {
  HORIZONTAL_STEP_INDICATOR_GLYPHS,
  horizontalStepperBreadcrumbSeparatorClass,
  horizontalStepperConnectorClass,
  horizontalStepperGlyphVariants,
  horizontalStepperLabelVariants,
  horizontalStepperStepVariants,
} from "@/lib/stepper-variants";
import { cn } from "@/lib/utils";
import {
  type HorizontalStepStatus,
  useStepInfo,
  useStepperContext,
} from "./horizontal-stepper-context";

const SR_LABEL: Record<HorizontalStepStatus, string> = {
  completed: "Completed: ",
  active: "Current: ",
  pending: "Upcoming: ",
};

/** Props for horizontal stepper step. */
export interface HorizontalStepperStepProps {
  /** Step id matched against the parent value to derive status. */
  value: string;
  /** Step label. */
  children: ReactNode;
  /** Additional class names merged onto the rendered element. */
  className?: string;
}

/** Single horizontal step (derives status from parent value) */
export function HorizontalStepperStep({ value, children, className }: HorizontalStepperStepProps) {
  const { variant } = useStepperContext();
  const { status, index } = useStepInfo(value);
  const showConnectorBefore = index > 0;

  const glyph = renderGlyph(variant, status);

  // For the `numbered` variant the connector lives in the step's pseudo-
  // element; we expose the completion state via `data-conn-completed` so the
  // CSS reads "completed connector = green line". Only `completed` steps fill
  // their incoming segment — the active step's incoming connector stays
  // border-coloured to read as still-in-progress, mirroring the vertical
  // stepper spec where only segments leading INTO a completed indicator turn
  // green.
  const isConnCompleted = status === "completed";

  return (
    <>
      {showConnectorBefore && variant === "ascii" && (
        <li role="presentation" aria-hidden="true" className="inline-flex items-center">
          <span
            data-completed={status === "completed" ? "true" : undefined}
            className={horizontalStepperConnectorClass}
          >
            ───
          </span>
        </li>
      )}
      {showConnectorBefore && variant === "breadcrumb" && (
        <li role="presentation" aria-hidden="true" className="inline-flex items-center">
          <span className={horizontalStepperBreadcrumbSeparatorClass}>/</span>
        </li>
      )}
      <li
        aria-current={status === "active" ? "step" : undefined}
        data-status={status}
        data-conn-completed={isConnCompleted ? "true" : undefined}
        className={cn(horizontalStepperStepVariants({ variant }), className)}
      >
        {glyph !== null && (
          <span className={cn(horizontalStepperGlyphVariants({ variant, status }))}>
            <span className="sr-only">{SR_LABEL[status]}</span>
            {glyph}
          </span>
        )}
        <span className={cn(horizontalStepperLabelVariants({ variant, status }))}>
          {glyph === null && <span className="sr-only">{SR_LABEL[status]}</span>}
          {children}
        </span>
      </li>
    </>
  );
}

function renderGlyph(
  variant: "ascii" | "numbered" | "breadcrumb",
  status: HorizontalStepStatus,
): ReactNode {
  if (variant === "numbered") {
    if (status === "completed") return "✓";
    return <span data-counter aria-hidden="true" />;
  }
  if (variant === "breadcrumb" && status === "pending") return null;
  const glyph = HORIZONTAL_STEP_INDICATOR_GLYPHS[variant][status];
  return glyph || null;
}

/*
 * Stepper variant CSS contract.
 *
 * Three things live in real CSS (not Tailwind utilities):
 *
 *   1. The `ascii` active-state blinking cursor (custom @keyframes). Wrapped
 *      in motion-safe Tailwind utility on the consuming side; the keyframes
 *      themselves are declared here.
 *   2. The `numbered` variant's CSS counter — the digit shown in pending and
 *      active states comes from `counter(step)` rendered through `::before`
 *      on the indicator span. Tailwind's arbitrary value support for
 *      `content-[counter(...)]` is unreliable across compilers.
 *   3. The vertical connector line between steps. Composed via utilities the
 *      connector clamped to a 2px sliver because `bottom: 0` plus a 30px
 *      `<li>` left no room to draw. Real CSS lets the line overshoot the
 *      `<li>` boundary so it visually bridges into the next indicator at any
 *      row height. The `left` offset is variant-specific and centred on the
 *      indicator column width (1ch ASCII → centred on the `x` in `[x]`, 20px
 *      numbered square → centred at 10px, 1ch bullet → centred at 4px).
 */

@keyframes stepper-blink {
  50% {
    opacity: 0;
  }
}

@media (prefers-reduced-motion: reduce) {
  /*
   * Keep the cursor visible but stop animating it. The .motion-safe: utility
   * on the consumer prevents the animation property from being set in the
   * first place, but this guard catches any direct usage of the keyframes
   * elsewhere.
   */
  [data-variant="ascii"] [data-stepper-cursor] {
    /* biome-ignore lint/complexity/noImportantStyles: prefers-reduced-motion override must defeat the cursor keyframes regardless of specificity. */
    animation: none !important;
  }
}

/*
 * Numbered indicator: render `counter(step)` for pending and active cells.
 * Completed/error/skipped/disabled render an explicit glyph in JSX and the
 * counter span is absent from the tree.
 *
 * The CSS counter is established on the <ol data-variant="numbered"> via the
 * `[counter-reset:step]` Tailwind utility and incremented on each <li> via
 * `[counter-increment:step]`. This rule paints the digit on the indicator
 * span whose JSX renders an empty `[data-counter]` placeholder.
 */
[data-variant="numbered"] [data-counter]::before {
  content: counter(step);
}

/*
 * Vertical connector — shared geometry for ASCII, numbered, and bullet
 * variants. `tag` and `progress` opt out (no rule). The `<li>` itself is
 * positioned `relative` via the Tailwind base. Scoped to
 * `[data-orientation="vertical"]` so the horizontal stepper's numbered
 * variant (which has its own behind-the-square horizontal bar) is untouched.
 *
 * `top: 36px` clears the indicator glyph (sits at row top with `py-4`, so
 * the glyph bottom edge lands at ~34px and the connector starts ~2px below).
 * `bottom: -8px` overshoots the `<li>` boundary modestly so the line visually
 * bridges into the next step's connector without dominating the row height —
 * the row breathes around a short connector segment rather than a long line.
 * The last step suppresses the connector.
 */
[data-orientation="vertical"][data-variant="ascii"] > li:not(:last-child)::before,
[data-orientation="vertical"][data-variant="numbered"] > li:not(:last-child)::before,
[data-orientation="vertical"][data-variant="bullet"] > li:not(:last-child)::before {
  content: "";
  position: absolute;
  top: 36px;
  bottom: -8px;
  width: 1px;
  background: var(--border);
}

/*
 * Per-variant horizontal alignment of the connector. Each value centres the
 * 1px line on the visual middle of the indicator column.
 */
[data-orientation="vertical"][data-variant="ascii"] > li:not(:last-child)::before {
  /* `[x]` is 3 mono chars wide; centre on the `x` (1.5ch from the left edge). */
  left: calc(1.5ch + 0.5px);
}

[data-orientation="vertical"][data-variant="numbered"] > li:not(:last-child)::before {
  /* 20px square indicator → centre at 10px (½px nudge keeps the 1px line crisp). */
  left: 9.5px;
  /* Square bottom sits at ~36px (16px paddingTop + 20px square). Push the
   * connector start 2px below the square so it doesn't paint over the border. */
  top: 38px;
}

[data-orientation="vertical"][data-variant="bullet"] > li:not(:last-child)::before {
  /* 1ch indicator → centre at ½ch. Dashed style differentiates the low-chrome variant. */
  left: calc(0.5ch + 0.5px);
  background: transparent;
  border-left: 1px dashed var(--border);
  width: 0;
}

/*
 * Completed steps recolour the connector so a finished segment reads as a
 * filled timeline. Bullet uses `border-left-color` because the connector is
 * a border, not a background.
 */
[data-orientation="vertical"][data-variant="ascii"]
  > li[data-status="completed"]:not(:last-child)::before,
[data-orientation="vertical"][data-variant="numbered"]
  > li[data-status="completed"]:not(:last-child)::before {
  background: var(--success);
}

[data-orientation="vertical"][data-variant="bullet"]
  > li[data-status="completed"]:not(:last-child)::before {
  border-left-color: var(--success);
}
